/**
 * Loads portfolio companies with a LinkedIn page.
 * Source of truth: paste from Projects/portfolio-intel/data/company-seed.json
 * or keep this Code node in sync after seed changes.
 */
const fsCompanies = [
  // Placeholder — replace by reading from static data below
];

// Embedded seed (linkedin_url required). Null LinkedIn companies are skipped.
const seed = $getWorkflowStaticData('global').companySeed
  || JSON.parse($('Seed Companies').first().json.seedJson || '[]');

const companies = seed.filter(c => c.linkedin_url);

return companies.map(c => ({
  json: {
    slug: c.slug,
    company_name: c.name,
    linkedin_url: String(c.linkedin_url).replace(/\/+$/, ''),
    website_url: c.website_url,
    run_id: $execution.id,
  }
}));

// Respect Apify concurrency — pause between companies
await new Promise(r => setTimeout(r, 4000));
return [$input.first()];

function normalize(url) {
  if (!url) return '';
  try {
    const u = new URL(String(url).trim());
    u.hash = '';
    u.search = '';
    let path = u.pathname.replace(/\/+$/, '').toLowerCase();
    path = path.replace(/\/(about|posts|jobs|people|insights)$/i, '');
    return 'https://www.linkedin.com' + path;
  } catch {
    return String(url).trim().replace(/\/+$/, '').toLowerCase();
  }
}

function authorMatches(authorUrl, companyUrl) {
  const a = normalize(authorUrl);
  const c = normalize(companyUrl);
  if (!a || !c) return false;
  if (a === c) return true;
  const cs = c.match(/\/company\/([^/]+)/)?.[1];
  const as = a.match(/\/company\/([^/]+)/)?.[1];
  return !!(cs && as && cs === as);
}

const company = $('Throttle 4s').item.json;
const companyUrl = company.linkedin_url;
const apifyRaw = $input.all();

// Apify sync endpoint returns an array of posts, or an error object
let posts = [];
let apifyError = null;
const first = apifyRaw[0]?.json;
if (Array.isArray(first)) {
  posts = first;
} else if (Array.isArray($input.first().json)) {
  posts = $input.first().json;
} else if (first?.error || first?.errorMessage) {
  apifyError = first.errorMessage || first.error || JSON.stringify(first);
} else if (first && (first.content || first.linkedinUrl || first.type === 'post')) {
  posts = apifyRaw.map(i => i.json);
} else if (Array.isArray(first?.data?.items)) {
  posts = first.data.items;
} else {
  // sometimes each item is a post already
  posts = apifyRaw.map(i => i.json).filter(p => p && (p.content || p.linkedinUrl));
}

const kept = [];
const filtered = [];

for (const p of posts) {
  if (!p || typeof p !== 'object') continue;
  const authorUrl = p.author?.linkedinUrl || p.author?.url || '';
  const authorType = (p.author?.type || '').toLowerCase();
  const postUrl = p.linkedinUrl || p.url || p.postUrl || '';
  const content = (p.content || p.text || p.postText || '').trim();
  const published =
    p.postedAt?.date ||
    (p.postedAt?.timestamp ? new Date(p.postedAt.timestamp).toISOString() : null) ||
    p.publishedAt ||
    null;

  if (!content || !postUrl) {
    filtered.push({ reason: 'missing_fields', post_url: postUrl });
    continue;
  }

  // Prefer explicit company author match; also accept missing authorUrl only if author.type === company
  const ok =
    (authorUrl && authorMatches(authorUrl, companyUrl)) ||
    (!authorUrl && authorType === 'company');

  if (!ok) {
    filtered.push({
      reason: 'author_mismatch',
      post_url: postUrl,
      author_url: authorUrl,
      author_type: authorType,
    });
    continue;
  }

  kept.push({
    company_name: company.company_name,
    company_slug: company.slug,
    linkedin_url: companyUrl,
    post_content: content,
    post_url: postUrl,
    published_at: published,
    author_url: authorUrl,
  });
}

return [{
  json: {
    company_name: company.company_name,
    company_slug: company.slug,
    linkedin_url: companyUrl,
    success: !apifyError,
    apify_error: apifyError,
    posts_raw: posts.length,
    posts_kept: kept.length,
    posts_filtered: filtered.length,
    filtered,
    posts: kept,
  }
}];

const summary = $input.first().json;
const posts = summary.posts || [];
if (!posts.length) {
  return [{ json: { ...summary, ingest_skipped: true, ingest_ok: 0, ingest_failed: 0 } }];
}

// Emit one item per post for HTTP node (with company context)
return posts.map(p => ({ json: { ...p, _meta: { company_slug: summary.company_slug, company_name: summary.company_name } } }));

