// Aggregate per-company outcome after post loop returns to batch
const company = $('Validate Author = Company Page').first().json;
const ingestResults = $input.all().map(i => i.json);

let ingest_ok = 0;
let ingest_failed = 0;
for (const r of ingestResults) {
  if (r.ok || r.inserted || r.updated || r.total != null) ingest_ok += 1;
  else if (r.error || r.message) ingest_failed += 1;
}

const line = {
  company_name: company.company_name,
  company_slug: company.company_slug,
  success: company.success,
  apify_error: company.apify_error || null,
  posts_raw: company.posts_raw,
  posts_kept: company.posts_kept,
  posts_filtered: company.posts_filtered,
  filtered_sample: (company.filtered || []).slice(0, 3),
  ingest_ok,
  ingest_failed,
};

return [{ json: line }];

const rows = $input.all().map(i => i.json);
const summary = {
  companies: rows.length,
  succeeded: rows.filter(r => r.success && !r.apify_error).length,
  failed: rows.filter(r => r.apify_error || r.success === false).length,
  posts_kept_total: rows.reduce((s, r) => s + (r.posts_kept || 0), 0),
  posts_filtered_total: rows.reduce((s, r) => s + (r.posts_filtered || 0), 0),
  ingest_ok_total: rows.reduce((s, r) => s + (r.ingest_ok || 0), 0),
  ingest_failed_total: rows.reduce((s, r) => s + (r.ingest_failed || 0), 0),
  per_company: rows,
  finished_at: new Date().toISOString(),
};
console.log(JSON.stringify(summary, null, 2));
return [{ json: summary }];
